const fs = require('fs');
const DATA_FILE = '/home/node/.n8n/zwangsversteigerungen_known_az.json';

function cleanHtml(str) {
  return String(str || '')
    .replace(/<!--[^>]*-->/g, '')
    .replace(/<[^>]+>/g, '')
    .replace(/&uuml;/g, 'ü').replace(/&auml;/g, 'ä').replace(/&ouml;/g, 'ö')
    .replace(/&Uuml;/g, 'Ü').replace(/&Auml;/g, 'Ä').replace(/&Ouml;/g, 'Ö')
    .replace(/&szlig;/g, 'ß').replace(/&amp;/g, '&').replace(/&nbsp;/g, ' ')
    .replace(/&#128;/g, '€').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/\s+/g, ' ').trim();
}

function esc(str) {
  return String(str || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function parseAktualisierung(block) {
  const m = block.match(/letzte Aktualisierung\s+(\d{2})-(\d{2})-(\d{4})\s+(\d{2}):(\d{2})/);
  if (!m) return null;
  return new Date(m[3] + '-' + m[2] + '-' + m[1] + 'T' + m[4] + ':' + m[5] + ':00');
}

const html = $input.first().json.data || '';
const cutoffTime = new Date(Date.now() - 25 * 60 * 60 * 1000);

let sentAz = {};
try {
  const raw = fs.readFileSync(DATA_FILE, 'utf8');
  sentAz = JSON.parse(raw).sentAz || {};
} catch (e) {
  sentAz = {};
}

const sevenDaysAgo = Date.now() - 7 * 24 * 60 * 60 * 1000;
for (const az of Object.keys(sentAz)) {
  if (sentAz[az] < sevenDaysAgo) delete sentAz[az];
}

const blocks = html.split(/<!--Aktenzeichen--->/);
const recentObjects = [];

for (let i = 1; i < blocks.length; i++) {
  const block = blocks[i];

  const aktualisierung = parseAktualisierung(block);
  if (!aktualisierung || aktualisierung < cutoffTime) continue;

  const azMatch = block.match(/<nobr>\s*([^<]+?)\s*&nbsp;\(Detailansicht\)\s*<\/nobr>/i);
  if (!azMatch) continue;
  const aktenzeichen = azMatch[1].trim();

  const zvgMatch = block.match(/href=index\.php\?button=showZvg&(?:amp;)?zvg_id=(\d+)&(?:amp;)?land_abk=(\w+)/i);
  const detailLink = zvgMatch
    ? 'https://www.zvg-portal.de/index.php?button=showZvg&zvg_id=' + zvgMatch[1] + '&land_abk=' + zvgMatch[2]
    : 'https://www.zvg-portal.de/index.php?button=Suchen';

  const lageMatch = block.match(/Objekt\/Lage<\/td>[\s\S]*?<b>([\s\S]*?)<\/b>([^<]*(?:<[^/][^>]*>[^<]*<\/[^>]+>[^<]*)*)/i);
  let lage = 'k.A.';
  if (lageMatch) {
    const typ = cleanHtml(lageMatch[1]).replace(/:$/, '').trim();
    const adresse = cleanHtml(lageMatch[2]).replace(/^[:\s]+/, '').trim();
    lage = typ + (adresse ? ': ' + adresse : '');
  }

  const vwMatch = block.match(/Verkehrswert[\s\S]*?<b>([^<]+)<\/b>/i);
  const verkehrswert = vwMatch ? cleanHtml(vwMatch[1]) : 'k.A.';

  const terminMatch = block.match(/Termin<\/td><td[^>]*colspan=2>([^<]+)/i);
  const termin = terminMatch ? cleanHtml(terminMatch[1]) : 'k.A.';

  recentObjects.push({ aktenzeichen, detailLink, lage, verkehrswert, termin });
}

const newObjects = recentObjects.filter(obj => !sentAz[obj.aktenzeichen]);

if (newObjects.length === 0) {
  fs.writeFileSync(DATA_FILE, JSON.stringify({ sentAz }));
  return [{ json: { hasObjects: false, telegramText: '', objectCount: 0 } }];
}

for (const obj of newObjects) {
  sentAz[obj.aktenzeichen] = Date.now();
}
fs.writeFileSync(DATA_FILE, JSON.stringify({ sentAz }));

let text = '';
newObjects.forEach((obj, i) => {
  text += '<b>' + (i + 1) + '. AZ: ' + esc(obj.aktenzeichen) + '</b>\n';
  text += 'Lage: ' + esc(obj.lage) + '\n';
  text += 'Termin: ' + esc(obj.termin) + '\n';
  text += 'Verkehrswert: ' + esc(obj.verkehrswert) + '\n';
  text += '<a href=\'' + obj.detailLink + '\'>Details ansehen</a>\n\n';
});

return [{ json: { hasObjects: true, telegramText: text, objectCount: newObjects.length } }];
